import os
import sys

def gather_logs(folder_path):
    """
    Collects community event logs from the given folder path.
    Ensures all files be kept safe and sorted properlike.
    """
    logs = []

    if not os.path.exists(folder_path):
        print(f"Ain't no folder at {folder_path}, y'all. Try another spot.")
        return logs

    try:
        for filename in os.listdir(folder_path):
            if filename.endswith('.log'):
                file_path = os.path.join(folder_path, filename)
                with open(file_path, 'r') as file:
                    logs.append(file.read())

        logs.sort(key=lambda x: len(x))
        print(f"Got {len(logs)} logs, all neat and tidy like.")
        return logs

    except Exception as e:
        print(f"Hit a snag: {e}. Best check them files again.")
        return []

if __name__ == "__main__":
    if len(sys.argv) > 1:
        logs = gather_logs(sys.argv[1])
        for log in logs:
            print(log[:100] + "...")  # Show just a snip like
    else:
        print("Y'all gotta give me a folder path, hear?")

